import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { FaRocket, FaEnvelope, FaLock } from "react-icons/fa";

const Login = () => {
  const navigate = useNavigate();

  const [form, setForm] = useState({
    email: '',
    password: ''
  });

  const handleChange = (e) => {
    setForm({
      ...form,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      const res = await axios.post(
        'http://localhost:5001/api/auth/login',
        {
          email: form.email,
          password: form.password
        }
      );

      localStorage.setItem("userId", res.data.userId);
      localStorage.setItem("userName", res.data.name);

      alert('Login Successful');
      navigate('/dashboard');

    } catch (err) {
      alert(err.response?.data || 'Error ❌');
    }
  };

  // 🔥 SAFE ARRAY (FIX)
  const particles = Array.from({ length: 10 });

  return (
    <div className="relative min-h-screen flex items-center justify-center overflow-hidden bg-[#020617]">

      {/* 🔥 MOVING BLOBS */}
      <motion.div
        animate={{ x: [0, 100, -100, 0], y: [0, -100, 100, 0] }}
        transition={{ duration: 15, repeat: Infinity }}
        className="absolute w-[500px] h-[500px] bg-purple-500/30 rounded-full blur-[120px] top-[-100px] left-[-100px]"
      />

      <motion.div
        animate={{ x: [0, -100, 100, 0], y: [0, 100, -100, 0] }}
        transition={{ duration: 18, repeat: Infinity }}
        className="absolute w-[400px] h-[400px] bg-blue-500/30 rounded-full blur-[120px] bottom-[-100px] right-[-100px]"
      />

      {/* 🔥 FLOATING ICONS (FIXED) */}
      <div className="absolute inset-0">
        {particles.map((_, i) => (
          <motion.div
            key={i}
            animate={{ y: [0, -20, 0] }}
            transition={{ duration: 3 + i, repeat: Infinity }}
            className="absolute text-white/20"
            style={{
              top: `${Math.random() * 100}%`,
              left: `${Math.random() * 100}%`
            }}
          >
            <FaRocket size={12} />
          </motion.div>
        ))}
      </div>

      {/* 🔥 CARD */}
      <motion.div
        initial={{ opacity: 0, y: 60 }}
        animate={{ opacity: 1, y: 0 }}
        className="relative z-10 backdrop-blur-2xl bg-white/10 border border-white/20 shadow-xl rounded-3xl p-8 w-full max-w-md text-white"
      >

        <h2 className="text-3xl font-bold text-center mb-4">
          Welcome Back 👋
        </h2>

        {/* ICON LINE */}
        <div className="flex justify-center gap-4 mb-6 text-2xl">

          <motion.div whileHover={{ scale: 1.2 }} className="text-purple-400">
            <FaRocket />
          </motion.div>

          <motion.div whileHover={{ scale: 1.2 }} className="text-blue-400">
            <FaEnvelope />
          </motion.div>

          <motion.div whileHover={{ scale: 1.2 }} className="text-pink-400">
            <FaLock />
          </motion.div>

        </div>

        <form className="space-y-5" onSubmit={handleSubmit}>

          <div className="relative">
            <FaEnvelope className="absolute left-3 top-4 text-white/50" />
            <input
              type="email"
              name="email"
              placeholder="Enter your email"
              value={form.email}
              onChange={handleChange}
              required
              className="w-full pl-10 py-3 rounded-xl bg-white/10 border border-white/20"
            />
          </div>

          <div className="relative">
            <FaLock className="absolute left-3 top-4 text-white/50" />
            <input
              type="password"
              name="password"
              placeholder="Enter password"
              value={form.password}
              onChange={handleChange}
              required
              className="w-full pl-10 py-3 rounded-xl bg-white/10 border border-white/20"
            />
          </div>

          <motion.button
            whileTap={{ scale: 0.95 }}
            type="submit"
            className="w-full py-3 rounded-xl bg-gradient-to-r from-indigo-500 to-purple-500 font-semibold"
          >
            Login
          </motion.button>

        </form>

        <p className="text-center text-sm mt-6">
          Don't have an account?
          <span
            onClick={() => navigate("/register")}
            className="ml-1 text-indigo-400 cursor-pointer"
          >
            Register
          </span>
        </p>

      </motion.div>

    </div>
  );
};

export default Login;
